var e=[{id:`L2_1`,type:`dialog`,speaker:`LONELY_NPC_SUMMER_NULL`,text:{KOREA:`항복! 항복입니다!`,JPN:`降伏！　降伏します！`,ENG:`Surrender! I surrender!`,TWN:`投降！我投降！`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`RIFLE_FOX_ENEMY_NULL`,face:`UNIT_IDLE`}}}},{id:`L3_1`,type:`dialog`,speaker:`LONELY_NPC_SUMMER_NULL`,text:{KOREA:`얌전히 교도소로 돌아갈 테니 쏘지만 말아주세요!`,JPN:`大人しく刑務所に戻りますから、撃たないでください！`,ENG:`I'll go back to prison. Please don't shoot!`,TWN:`我會乖乖回監獄的，請別開槍！`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`RIFLE_FOX_ENEMY_NULL`,face:`UNIT_IDLE`}}}},{id:`L4_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_NULL`,text:{KOREA:`뭐야? 이 음침한 여자는!`,JPN:`何だ？　この陰気な女は！`,ENG:`Who's this gloomy-looking woman?`,TWN:`搞什麼？這個陰沉的女人！`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`RIFLE_FOX_ENEMY_NULL`,face:`UNIT_IDLE`}}}},{id:`L5_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_NULL`,text:{KOREA:`너한텐 볼 일 없으니 저리 비켜!`,JPN:`お前に用はない、どけ！`,ENG:`We've got no business with you. Buzz off!`,TWN:`這與你無關，給我讓開！`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`RIFLE_FOX_ENEMY_NULL`,face:`UNIT_IDLE`}}}},{id:`L8_1`,type:`dialog`,speaker:`LONELY_NPC_SUMMER_NULL`,text:{KOREA:`꺄아악!`,JPN:`きゃああっ！`,ENG:`Kyaaah!`,TWN:`啊啊啊！`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:{char_id:`RIFLE_FOX_ENEMY_NULL`,face:`UNIT_IDLE`},C:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`CHAIR_SCHOOL_SUMMER_NULL`,text:{KOREA:`쿠울......`,JPN:`すやすや……`,ENG:`Zzz...`,TWN:`呼呼……`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:{char_id:`CHAIR_SCHOOL_SUMMER_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_NULL`,text:{KOREA:`여기 있었군! 다들, 타겟을 확보했다!`,JPN:`ここにいたか！　みんな、ターゲットを確保した！`,ENG:`There she is! Guys, I've secured our target!`,TWN:`在這裡！確定目標了！`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:{char_id:`CHAIR_SCHOOL_SUMMER_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`RIFLE_FOX_ENEMY_NULL`,face:`UNIT_IDLE`}}}},{id:`L13_1`,type:`dialog`,speaker:`RIFLE_FOX_ENEMY_NULL`,text:{KOREA:`전투 중단하고 지체 없이 빠져나간다!`,JPN:`戦闘を中止してただちに退却するぞ！`,ENG:`Let's stop fighting and get out of here now!`,TWN:`停止戰鬥，快速撤離現場！`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:{char_id:`CHAIR_SCHOOL_SUMMER_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`RIFLE_FOX_ENEMY_NULL`,face:`UNIT_IDLE`}}}},{id:`L15_1`,type:`dialog`,speaker:`LONELY_NPC_SUMMER_NULL`,text:{KOREA:`휴우...... 날 노린게 아니라서 정말 다행이야......`,JPN:`ふう……私を狙いに来たんじゃないのか。よかった……`,ENG:`Phew! Thank God, they didn't come for me!`,TWN:`呼……還好不是來找我的，真是太好了……`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:null,C:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`PRESIDENT_SCHOOL_SUMMER_NULL`,text:{KOREA:`이런! 이디스!`,JPN:`しまった！　イーディス！`,ENG:`Oh, no! Edith!`,TWN:`啊！伊蒂絲！`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:null,C:{char_id:`PRESIDENT_SCHOOL_SUMMER_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`CHAIR_SCHOOL_SUMMER_NULL`,text:{KOREA:`......음?`,JPN:`……うん？`,ENG:`Mm?`,TWN:`……嗯？`},stage:{bg:`HELI_NORMAL`,slots:{L:null,C:{char_id:`CHAIR_SCHOOL_SUMMER_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`CHAIR_SCHOOL_SUMMER_NULL`,text:{KOREA:`쿠울......`,JPN:`すやすや……`,ENG:`Zzz...`,TWN:`呼呼……`},stage:{bg:`HELI_NORMAL`,slots:{L:null,C:{char_id:`CHAIR_SCHOOL_SUMMER_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`LONELY_NPC_SUMMER_NULL`,text:{KOREA:`저, 저런~! 소녀가 납치를 당하고 있네요. 뭔가 좋은 방법이 없으려나?`,JPN:`ど、どうしよう～！　少女が拉致されました。何かいい方法はないですか！`,ENG:`Oh, no! They're taking her away! Isn't there anything we can do?`,TWN:`哎呀～！那個少女要被綁架了呢，沒有什麼好辦法嗎？`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:null,C:{char_id:`LONELY_NPC_SUMMER_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_APSUMMER_NULL`,text:{KOREA:`곤란하네요. 공중은 제 전문 분야가 아닌데......`,JPN:`困りましたね。空中は私の専門じゃないので……`,ENG:`I don't know. Anti-air warfare is not my specialty.`,TWN:`傷腦筋啊，空戰不是我的專門領域的說……`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_APSUMMER_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_APSUMMER_NULL`,text:{KOREA:`이럴 때 제 파트너 아가씨가 계셨다면 이렇게 피융~ 하고 한방에......`,JPN:`こんな時に、私のパートナーがいたらサクッと一発で……`,ENG:`I wish my partner lady was here. With a pop, she could have shot them down at once.`,TWN:`如果這種時候有我的搭檔小姐在，''碰''的一下就能……`},stage:{bg:`SUMMER_SWIMPOOL`,slots:{L:null,C:{char_id:`JOOSHIYOON_FENRIR_APSUMMER_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L32_1`,type:`dialog`,speaker:null,text:{KOREA:`뭐야? 뭐가 날아온 거야!`,JPN:`何だ？　何か飛んで来たぞ！`,ENG:`What? What was that?`,TWN:`什麼？有什麼東西飛過來了！`},stage:{bg:`SKY`,slots:{L:null,C:{char_id:`HELI_STATE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};